    description: ?[:0]const u8,
    ocr_result: ?ExtractionResult,
    bounding_box: ?[:0]const u8,
    source_path: ?[:0]const u8,
    image_kind: ?ImageKind,
    kind_confidence: ?f32,
    cluster_id: ?u32,
};

